function [u,covar,t,iter,fitImg,fitX,fitY] = fFitGaus2DV01(x,y,img,rat)% Perform fitting to 2d Gaussian distribution%% [u,covar,t,iter,fitImg,fitX,fitY] = fFitGausV01(x,cnts,ratio)% x: axis information (x axis)% y: counts for each point (yaxis)% img: source image% rat: difine threshold to fit, 0.2 will cut below 0.2 x peak%% u: fitted mean for each gaussian (each mean is a 2x1 vector)% covar   - fitted covariance for each gaussian. this is a 2x2xM matrix.% t       - probability of each gaussian in the complete distribution% iter    - number of iterations done by the function% fitImg  - image used for fitting% fitX,fitY - axes for fitting%  %%%%%%%%%%%%%%%%%%%%%%%%%%%%% Fit Gaussian 2D, ver.1%% Kei Nakamura% Created on Friday, February 12th 2010.% Modified on %% ver.1: created%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body% preform ROi with threshold defined by "rat"[szy,szx] = size(img);[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:szx],sum(img),rat);    % for roix1 = round(peak-wLOut); x2 = round(peak+wHOut);[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:szy],sum(img,2),rat);    % for roiy1 = round(peak-wLOut); y2 = round(peak+wHOut);fitImg = img(y1:y2,x1:x2);   % image for 2D-fittingfitX = x(x1:x2); fitY = y(y1:y2);   % axis for fitting% making array for fitting functionhst = fGetHst2DV01(fitX,fitY,fitImg);[u,covar,t,iter] = fit_mix_2D_gaussian(hst,1);
